import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";
import { Navbar } from "@/components/Navbar";
import { getAllProjects, deleteProject } from "@/lib/firebaseUtils";
import { useAuth } from "@/contexts/AuthContext";
import { AddProject } from "@/components/AddProject";
import { ProjectCard } from "@/components/ProjectCard";
import type { Project } from "@/lib/firebaseUtils";
import { navItems } from "@/lib/data";

const Dashboard = () => {
  const [projects, setProjects] = useState<Project[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [showAddProject, setShowAddProject] = useState(false);
  const { user } = useAuth();
  const { toast } = useToast();
  const navigate = useNavigate();

  useEffect(() => {
    fetchProjects();
  }, []);

  const fetchProjects = async () => {
    setIsLoading(true);
    try {
      const fetchedProjects = await getAllProjects();
      setProjects(fetchedProjects);
    } catch (error: any) {
      toast({
        variant: "destructive",
        title: "Error",
        description: "Failed to fetch projects",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleAddProject = () => {
    setShowAddProject(true);
  };

  const handleProjectAdded = () => {
    setShowAddProject(false);
    fetchProjects();
  };

  const handleDeleteProject = async (projectId: string) => {
    if (window.confirm('Are you sure you want to delete this project?')) {
      try {
        await deleteProject(projectId);
        toast({
          title: "Success",
          description: "Project deleted successfully",
        });
        fetchProjects();
      } catch (error: any) {
        toast({
          variant: "destructive",
          title: "Error",
          description: "Failed to delete project",
        });
      }
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-gray-900" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      <Navbar items={navItems} />
      <div className="container mx-auto px-4 py-8">
        <div className="flex justify-between items-center mb-8">
          <h1 className="text-3xl font-bold">Dashboard</h1>
          <Button onClick={handleAddProject}>Add New Project</Button>
        </div>

        {showAddProject && (
          <AddProject onSuccess={handleProjectAdded} onCancel={() => setShowAddProject(false)} />
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {projects.map((project) => (
            <ProjectCard
              key={project.id}
              project={project}
              onDelete={() => handleDeleteProject(project.id)}
              isAdmin={true}
            />
          ))}
        </div>

        {projects.length === 0 && !isLoading && (
          <div className="text-center py-12">
            <p className="text-lg text-gray-600">No projects found. Add your first project!</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
